mapper.select:
SELECT id, supply_id, title, type, category, status, user_id, company_name, contact_name, contact_phone, email, location, description, specifications, price, capacity, publish_date, tags, advantages, certifications, view_count, created_at, updated_at FROM supply_supplies WHERE 1=1
AND (title LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%') OR company_name LIKE CONCAT('%', #{keyword}, '%') OR tags LIKE CONCAT('%', #{keyword}, '%'))
AND type = #{type}
AND status = #{status}
ORDER BY publish_date DESC, created_at DESC

mapper.update:
UPDATE supply_supplies
SET view_count = view_count + 1
WHERE id = #{id}
